prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?reachable ?reachableName ?reachableType WHERE {
  <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-C4E26F66-018C-4395-BD12-4992568F7C4C> ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?reachable .
  OPTIONAL { ?reachable bbo:name ?reachableName . }
  OPTIONAL { ?reachable a ?reachableType . }
  FILTER(CONTAINS(LCASE(STR(?reachableName)), LCASE("opis resenja")))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?gateway ?gatewayName ?gatewayType ?direction WHERE {
  ?gateway a bboExt:ExclusiveGateway .
  ?gateway tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_edab148c_8f79_4e08_b9b1_b11f3b1a0c1f> .
  OPTIONAL { ?gateway bbo:name ?gatewayName . }
  OPTIONAL { ?gateway bboExt:gatewayDirection ?direction . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?pathNode ?pathNodeName ?nodeType WHERE {
  <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-C4E26F66-018C-4395-BD12-4992568F7C4C> ((^bbo:has_sourceRef)/bbo:has_targetRef)* ?pathNode .
  <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-FA0ED846-A8E6-4A69-97BD-EF9B8B93F2DB> (^bbo:has_targetRef/^bbo:has_sourceRef)* ?pathNode .
  OPTIONAL { ?pathNode bbo:name ?pathNodeName . }
  OPTIONAL { ?pathNode a ?nodeType . }
}
LIMIT 50
